const FLAG_ICON_SIZES = { small: 16, medium: 24 };

export const FlagIcon = forwardRef(function FlagIcon(
  { name, size = 'medium', className, style, ...props },
  ref
) {
  const iconInfo = flagIconData[name];
  if (!iconInfo) { console.warn(`FlagIcon "${name}" not found`); return null; }
  const dimension = typeof size === 'number' ? size : FLAG_ICON_SIZES[size] || FLAG_ICON_SIZES.medium;
  const { viewBox, content } = iconInfo;
  return (
    <svg
      ref={ref}
      width={dimension}
      height={dimension}
      viewBox={viewBox}
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      className={className}
      style={{ display: 'inline-block', verticalAlign: 'middle', ...style }}
      aria-hidden="true"
      dangerouslySetInnerHTML={{ __html: content }}
      {...props}
    />
  );
});

export const flagIconNames = Object.keys(flagIconData);
export const getFlagIconNames = () => flagIconNames;
